Here's a `ProductDetailViewModel` using the MVVM pattern with `INotifyPropertyChanged`:

```csharp
using System.ComponentModel;
using System.Runtime.CompilerServices;
using System.Windows.Input;

public class ProductDetailViewModel : INotifyPropertyChanged
{
    private string _name = string.Empty;
    private decimal _price;
    private bool _isAvailable;

    public string Name
    {
        get => _name;
        set => SetProperty(ref _name, value);
    }

    public decimal Price
    {
        get => _price;
        set => SetProperty(ref _price, value);
    }

    public bool IsAvailable
    {
        get => _isAvailable;
        set => SetProperty(ref _isAvailable, value);
    }

    public ICommand LoadCommand { get; }

    public ProductDetailViewModel()
    {
        LoadCommand = new Command(async () => await LoadDataAsync());
    }

    private async Task LoadDataAsync()
    {
        // Replace with your actual data fetching logic
        await Task.Delay(500);

        Name = "Sample Product";
        Price = 29.99m;
        IsAvailable = true;
    }

    public event PropertyChangedEventHandler? PropertyChanged;

    private bool SetProperty<T>(ref T field, T value, [CallerMemberName] string? propertyName = null)
    {
        if (EqualityComparer<T>.Default.Equals(field, value))
            return false;

        field = value;
        PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
        return true;
    }
}
```

**Key points:**

- `SetProperty` raises `PropertyChanged` only when the value actually changes, avoiding unnecessary UI updates.
- `[CallerMemberName]` automatically captures the property name.
- `Command` wraps the async method so it can be bound to a button's `Command` property.

**Alternatively**, if you use the [CommunityToolkit.Mvvm](https://www.nuget.org/packages/CommunityToolkit.Mvvm) NuGet package, this collapses to:

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;

public partial class ProductDetailViewModel : ObservableObject
{
    [ObservableProperty]
    private string _name = string.Empty;

    [ObservableProperty]
    private decimal _price;

    [ObservableProperty]
    private bool _isAvailable;

    [RelayCommand]
    private async Task LoadDataAsync()
    {
        await Task.Delay(500);
        Name = "Sample Product";
        Price = 29.99m;
        IsAvailable = true;
    }
}
```

The source generators produce the public properties and `LoadDataCommand` automatically.
